import React, { useState, useEffect } from 'react';
import { Package, Bike, CheckCircle2, Store, Home } from 'lucide-react';

const SeguimientoPedido = ({ pedido, onFinalizar }) => {
  const [fase, setFase] = useState(1); 
  const [progreso, setProgreso] = useState(0);
  const [horaLlegada, setHoraLlegada] = useState("");

  useEffect(() => {
    // Cálculo de hora real basado en el momento de la compra
    const ahora = new Date();
    ahora.setMinutes(ahora.getMinutes() + 30);
    const horaFormateada = ahora.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    const horaFinFormateada = new Date(ahora.getTime() + 15 * 60000).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
    setHoraLlegada(`${horaFormateada} - ${horaFinFormateada}`);

    const tiempoFase1 = 8000; // 8s Preparación
    const tiempoFase2 = 10000; // 10s Envío
    const intervaloMs = 100;

    const timer = setInterval(() => {
      setProgreso((prev) => {
        if (fase === 1) {
          if (prev >= 100) { setFase(2); return 0; }
          return prev + (100 / (tiempoFase1 / intervaloMs));
        } else if (fase === 2) {
          if (prev >= 100) { setFase(3); clearInterval(timer); return 100; }
          return prev + (100 / (tiempoFase2 / intervaloMs));
        }
        return 100;
      });
    }, intervaloMs);

    if (fase === 3) {
      const finalTimeout = setTimeout(() => { if (onFinalizar) onFinalizar(pedido.id); }, 5000);
      return () => clearTimeout(finalTimeout);
    }
    return () => clearInterval(timer);
  }, [fase, pedido.id, onFinalizar]);

  return (
    <div style={card}>
      {/* Cabecera con Hora Real y Estado Dinámico */}
      <div style={header}>
        <div style={infoEntrega}>
          <span style={textChico}>Llegada estimada</span>
          <div style={badgeEnHora}>EN HORA</div>
          <h2 style={horaEstilo}>{fase === 3 ? "¡ENTREGADO!" : horaLlegada}</h2>
        </div>
        <div style={cajaIconoPrincipal}>
          {fase === 1 && <Package size={28} color="white" />}
          {fase === 2 && <Bike size={28} color="white" />}
          {fase === 3 && <CheckCircle2 size={28} color="white" />}
        </div>
      </div>

      {/* TRAYECTO: LOCAL -> BARRA -> CASA */}
      <div style={contenedorTrayecto}>
        <Store size={20} color={fase >= 1 ? "#e67e22" : "#cbd5e1"} />
        
        <div style={contenedorBarra}>
          {[1, 2, 3, 4].map((seg) => {
            let llenado = 0;
            if (fase === 1) {
              if (seg === 1) llenado = Math.min(progreso * 2, 100);
              if (seg === 2) llenado = progreso > 50 ? (progreso - 50) * 2 : 0;
            } else if (fase >= 2) {
              if (seg <= 2) llenado = 100;
              if (seg === 3) llenado = fase === 3 ? 100 : Math.min(progreso * 2, 100);
              if (seg === 4) llenado = fase === 3 ? 100 : (progreso > 50 ? (progreso - 50) * 2 : 0);
            }
            return (
              <div key={seg} style={segmentoGris}>
                <div style={{ ...segmentoColor, width: `${llenado}%` }} />
              </div>
            );
          })}
        </div>

        <Home size={20} color={fase === 3 ? "#e67e22" : "#cbd5e1"} />
      </div>

      {/* Footer con Texto de Estado */}
      <div style={estadoFooter}>
        <div style={textoConIcono}>
          {fase === 2 && <Bike size={16} color="#e67e22" style={{marginRight: '8px'}} />}
          <span style={textoEstado}>
            {fase === 1 && "El local está preparando tu pedido..."}
            {fase === 2 && "El cadete está enviando tu pedido"}
            {fase === 3 && "¡Entregamos tu pedido! ¡Buen provecho!"}
          </span>
        </div>
      </div>
    </div>
  );
};

// --- ESTILOS ---
const card = { background: 'white', padding: '24px', borderRadius: '18px', boxShadow: '0 10px 25px rgba(0,0,0,0.05)', border: '1px solid #f1f5f9', marginBottom: '20px' };
const header = { display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '25px' };
const infoEntrega = { display: 'flex', flexDirection: 'column' };
const textChico = { fontSize: '12px', color: '#64748b', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.5px' };
const badgeEnHora = { background: '#27ae60', color: 'white', padding: '2px 8px', borderRadius: '4px', fontSize: '10px', fontWeight: 'bold', width: 'fit-content', margin: '6px 0' };
const horaEstilo = { margin: 0, fontSize: '26px', fontWeight: '800', color: '#1e293b' };

const cajaIconoPrincipal = { background: '#e67e22', width: '50px', height: '50px', borderRadius: '12px', display: 'flex', alignItems: 'center', justifyContent: 'center' };

const contenedorTrayecto = { display: 'flex', alignItems: 'center', gap: '12px', marginBottom: '20px' };
const contenedorBarra = { flex: 1, display: 'flex', gap: '6px' };
const segmentoGris = { flex: 1, height: '6px', background: '#f1f5f9', borderRadius: '10px', overflow: 'hidden' };
const segmentoColor = { height: '100%', background: '#e67e22', transition: 'width 0.1s linear' };

const estadoFooter = { borderTop: '1px solid #f8fafc', paddingTop: '15px' };
const textoConIcono = { display: 'flex', alignItems: 'center' };
const textoEstado = { fontSize: '15px', fontWeight: '700', color: '#1e293b' };

export default SeguimientoPedido;
